CREATE TABLE public.history_filter_presets (id uuid NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, user_id uuid NOT NULL, tenant_id text, name text NOT NULL, filters jsonb NOT NULL DEFAULT '{}'::jsonb, is_default boolean NOT NULL DEFAULT false, created_at timestamp with time zone NOT NULL DEFAULT now(), updated_at timestamp with time zone NOT NULL DEFAULT now()); CREATE INDEX idx_hfp_user ON public.history_filter_presets(user_id); CREATE INDEX idx_hfp_user_tenant ON public.history_filter_presets(user_id, tenant_id); CREATE UNIQUE INDEX uq_hfp_user_tenant_name ON public.history_filter_presets(user_id, COALESCE(tenant_id, ''), lower(name)); GRANT SELECT, INSERT, UPDATE, DELETE ON public.history_filter_presets TO authenticated; GRANT ALL ON public.history_filter_presets TO service_role; ALTER TABLE public.history_filter_presets ENABLE ROW LEVEL SECURITY; CREATE POLICY "hfp read own or super" ON public.history_filter_presets FOR SELECT TO authenticated USING (user_id = auth.uid() OR public.is_super_admin(auth.uid())); CREATE POLICY "hfp insert own" ON public.history_filter_presets FOR INSERT TO authenticated WITH CHECK (user_id = auth.uid()); CREATE POLICY "hfp update own" ON public.history_filter_presets FOR UPDATE TO authenticated USING (user_id = auth.uid()) WITH CHECK (user_id = auth.uid()); CREATE POLICY "hfp delete own" ON public.history_filter_presets FOR DELETE TO authenticated USING (user_id = auth.uid()); CREATE TRIGGER trg_hfp_touch BEFORE UPDATE ON public.history_filter_presets FOR EACH ROW EXECUTE FUNCTION public.touch_updated_at();